#[cfg(test)]
mod tests {
    use super::try_answer;

    fn ans(s: &str) -> Option<String> {
        try_answer(s)
    }

    #[test]
    fn arithmetic() {
        assert_eq!(ans("1+2").as_deref(), Some("3"));
        assert_eq!(ans("(3+4)*2").as_deref(), Some("14"));
        assert_eq!(ans("2^10").as_deref(), Some("1024"));
        assert_eq!(ans("17 % 5").as_deref(), Some("2"));
        assert_eq!(ans("10 / 4").as_deref(), Some("2.5"));
    }

    #[test]
    fn functions_and_constants() {
        assert_eq!(ans("sqrt(144)").as_deref(), Some("12"));
        assert_eq!(ans("5!").as_deref(), Some("120"));
        assert_eq!(ans("factorial of 6").as_deref(), Some("720"));
        assert_eq!(ans("gcd(48, 36)").as_deref(), Some("12"));
        assert_eq!(ans("fib(10)").as_deref(), Some("55"));
        assert_eq!(ans("is 17 prime").as_deref(), Some("1"));
        // pi*2 ≈ tau
        assert_eq!(ans("tau").as_deref(), ans("pi*2").as_deref());
    }

    #[test]
    fn natural_language() {
        assert_eq!(ans("what is 12 * 7?").as_deref(), Some("84"));
        assert_eq!(ans("20% of 50").as_deref(), Some("10"));
        assert_eq!(ans("square root of 81").as_deref(), Some("9"));
        assert_eq!(ans("9 squared").as_deref(), Some("81"));
    }

    #[test]
    fn not_math_returns_none() {
        assert_eq!(ans("ls -la"), None);
        assert_eq!(ans("echo 5"), None);
        assert_eq!(ans("what is the weather in paris"), None);
        assert_eq!(ans("open wikipedia"), None);
        assert_eq!(ans("5 5"), None);
    }

    #[test]
    fn base_conversion() {
        assert_eq!(ans("0xff").as_deref(), Some("255"));
        assert_eq!(ans("0b1010").as_deref(), Some("10"));
        assert_eq!(ans("255 in hex").as_deref(), Some("0xff"));
        assert_eq!(ans("10 to binary").as_deref(), Some("0b1010"));
        assert_eq!(ans("binary 1010").as_deref(), Some("10"));
    }

    #[test]
    fn unit_conversion() {
        assert_eq!(ans("100 c in f").as_deref(), Some("212"));
        assert_eq!(ans("32 f to c").as_deref(), Some("0"));
        assert_eq!(ans("2 hours in minutes").as_deref(), Some("120"));
        assert_eq!(ans("1 mile in km").as_deref(), Some("1.609344"));
        assert!(ans("10 km to miles").unwrap().starts_with("6.21"));
    }
}
